// 🎯 Enhanced Lead Enrichment Processor
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      message: 'No leads ready for enrichment',
      timestamp: new Date().toISOString(),
      leads_processed: 0
    }
  }];
}

console.log(`🎯 Processing ${items.length} leads for comprehensive enrichment`);

const enrichmentQueue = [];
let validLeadsCount = 0;

for (const item of items) {
  const lead = item.json.fields || item.json;

  // Enhanced validation for required fields
  const hasEmail = lead['Email'] && lead['Email'].trim() !== '';
  const hasName = lead['Full Name'] && lead['Full Name'].trim() !== '';
  const hasCompany = lead['Company Name'] && lead['Company Name'].trim() !== '';
  const hasLinkedIn = lead['Personal LinkedIn URL'] && lead['Personal LinkedIn URL'].trim() !== '';

  if (!hasEmail || !hasName || !hasCompany) {
    console.log(`⚠️ Skipping lead ${lead['Full Name'] || 'Unknown'} - missing critical data (Email: ${hasEmail}, Name: ${hasName}, Company: ${hasCompany})`);
    continue;
  }

  validLeadsCount++;

  // Prepare comprehensive enrichment data
  const enrichmentData = {
    // Core identifiers
    record_id: lead.id || lead['Record ID'],
    apollo_id: lead['Apollo ID'],
    session_id: lead['Session ID'],

    // Contact information
    full_name: lead['Full Name'],
    first_name: lead['First Name'],
    last_name: lead['Last Name'],
    email: lead['Email'],
    phone: lead['Phone'] || '',

    // Professional information
    job_title: lead['Job Title'],
    seniority_level: lead['Seniority Level'],
    personal_linkedin_url: lead['Personal LinkedIn URL'],

    // Company information
    company_name: lead['Company Name'],
    company_website: lead['Company Website'] || '',
    company_linkedin: lead['Company LinkedIn'] || '',
    company_industry: lead['Company Industry'],
    company_size: parseInt(lead['Company Size']) || 0,
    company_revenue: parseFloat(lead['Company Revenue']) || 0,
    funding_status: lead['Funding Status'],
    country: lead['Country'],

    // Current processing status
    processing_status: lead['Processing Status'],
    search_type: lead['Search Type'],
    search_priority: lead['Search Priority'],
    current_email_status: lead['Email Status'],
    current_email_confidence: parseInt(lead['Email Confidence']) || 0,
    outreach_priority: lead['Outreach Priority'],
    data_quality: lead['Data Quality'],

    // Service context
    target_industry: lead['Target Industry'],
    outreach_focus: lead['Outreach Focus'],
    service_offering: lead['Service Offering'],

    // Enrichment tracking
    enrichment_timestamp: new Date().toISOString(),
    enrichment_phase: 'email_validation',
    enrichment_batch_id: `batch_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,

    // Validation flags
    has_linkedin: hasLinkedIn,
    has_company_website: lead['Company Website'] && lead['Company Website'].trim() !== '',
    needs_email_validation: true,
    needs_linkedin_scraping: hasLinkedIn,
    needs_company_research: true,
    needs_website_analysis: lead['Company Website'] && lead['Company Website'].trim() !== ''
  };

  enrichmentQueue.push({ json: enrichmentData });
}

console.log(`✅ Prepared ${validLeadsCount} valid leads for enrichment pipeline`);
console.log(`❌ Skipped ${items.length - validLeadsCount} leads due to missing data`);

// Add batch summary
if (enrichmentQueue.length > 0) {
  enrichmentQueue.push({
    json: {
      batch_summary: true,
      total_leads_processed: items.length,
      valid_leads_for_enrichment: validLeadsCount,
      skipped_leads: items.length - validLeadsCount,
      batch_id: enrichmentQueue[0].json.enrichment_batch_id,
      timestamp: new Date().toISOString(),
      next_phase: 'email_validation'
    }
  });
}

return enrichmentQueue;

// 🔄 Domain Extractor for Apollo Enrichment
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      error: 'No LinkedIn company data received',
      success: false
    }
  }];
}

const processedResults = [];
const domainsArray = [];

for (const item of items) {
  const data = item.json;

  // Extract domain from company website
  let domain = '';
  const website = data.linkedin_company_website || data.company_website || '';

  if (website) {
    try {
      // Remove protocol and www
      domain = website.replace(/^https?:\/\//i, '')
                    .replace(/^www\./i, '')
                    .split('/')[0]
                    .split('?')[0];

      if (domain && domain.includes('.')) {
        domainsArray.push(domain);
      }
    } catch (error) {
      console.log(`Failed to extract domain from: ${website}`);
    }
  }

  const enrichedData = {
    ...data,
    extracted_domain: domain,
    ready_for_apollo_enrichment: domain ? true : false
  };

  processedResults.push({ json: enrichedData });
}

// Create batch request for Apollo (max 10 domains per request)
const batchResults = [];
for (let i = 0; i < domainsArray.length; i += 10) {
  const batch = domainsArray.slice(i, i + 10);
  batchResults.push({
    json: {
      company_domains_array: batch,
      batch_number: Math.floor(i / 10) + 1,
      total_domains: batch.length,
      apollo_enrichment_ready: true
    }
  });
}

console.log(`🔄 Prepared ${batchResults.length} Apollo enrichment batches for ${domainsArray.length} domains`);

return batchResults.length > 0 ? batchResults : processedResults;

// 🏢 Advanced Apollo Company Enrichment Formatter
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      error: 'No Apollo enrichment data received',
      success: false,
      apollo_enrichment_complete: false
    }
  }];
}

const formattedResults = [];

for (const item of items) {
  const data = item.json;

  // Check if we have valid Apollo enrichment data
  if (data.organizations && Array.isArray(data.organizations) && data.organizations.length > 0) {
    console.log(`🏢 Processing Apollo enrichment data for ${data.organizations.length} companies`);

    for (const company of data.organizations) {
      // === CORE COMPANY INFORMATION ===
      const coreInfo = {
        apollo_company_id: company.id || '',
        company_name: company.name || '',
        primary_domain: company.primary_domain || '',
        website_url: company.website_url || '',
        industry: company.industry || '',
        founded_year: company.founded_year || null,
        estimated_employees: company.estimated_num_employees || 0
      };

      // === CONTACT INFORMATION ===
      const contactInfo = {
        primary_phone: company.primary_phone?.number || company.phone || '',
        sanitized_phone: company.sanitized_phone || '',
        linkedin_url: company.linkedin_url || '',
        linkedin_uid: company.linkedin_uid || '',
        twitter_url: company.twitter_url || '',
        facebook_url: company.facebook_url || '',
        blog_url: company.blog_url || '',
        crunchbase_url: company.crunchbase_url || ''
      };

      // === BUSINESS INTELLIGENCE ===
      const businessIntel = {
        languages: company.languages || [],
        publicly_traded: company.publicly_traded_symbol ? true : false,
        stock_symbol: company.publicly_traded_symbol || '',
        stock_exchange: company.publicly_traded_exchange || '',
        alexa_ranking: company.alexa_ranking || null,
        logo_url: company.logo_url || ''
      };

      // === ADVANCED KEYWORD ANALYSIS ===
      const keywords = company.keywords || [];

      // Categorize keywords for better targeting
      const keywordCategories = {
        technology_keywords: [],
        service_keywords: [],
        industry_keywords: [],
        government_keywords: [],
        security_keywords: [],
        automation_keywords: [],
        process_keywords: []
      };

      keywords.forEach(keyword => {
        const lowerKeyword = keyword.toLowerCase();

        // Technology indicators
        if (lowerKeyword.includes('it ') || lowerKeyword.includes('software') || 
            lowerKeyword.includes('tech') || lowerKeyword.includes('system') ||
            lowerKeyword.includes('data') || lowerKeyword.includes('cloud')) {
          keywordCategories.technology_keywords.push(keyword);
        }

        // Service indicators
        else if (lowerKeyword.includes('service') || lowerKeyword.includes('support') ||
                lowerKeyword.includes('consulting') || lowerKeyword.includes('solution')) {
          keywordCategories.service_keywords.push(keyword);
        }

        // Government/Federal indicators
        else if (lowerKeyword.includes('government') || lowerKeyword.includes('federal') ||
                lowerKeyword.includes('gsa') || lowerKeyword.includes('contract')) {
          keywordCategories.government_keywords.push(keyword);
        }

        // Security indicators
        else if (lowerKeyword.includes('security') || lowerKeyword.includes('classified') ||
                lowerKeyword.includes('defense') || lowerKeyword.includes('nsa')) {
          keywordCategories.security_keywords.push(keyword);
        }

        // Automation opportunities
        else if (lowerKeyword.includes('automat') || lowerKeyword.includes('integrat') ||
                lowerKeyword.includes('workflow') || lowerKeyword.includes('process')) {
          keywordCategories.automation_keywords.push(keyword);
        }

        // Process indicators
        else if (lowerKeyword.includes('management') || lowerKeyword.includes('operation') ||
                lowerKeyword.includes('admin') || lowerKeyword.includes('procurement')) {
          keywordCategories.process_keywords.push(keyword);
        }

        // Industry-specific
        else {
          keywordCategories.industry_keywords.push(keyword);
        }
      });

      // === AUTOMATION OPPORTUNITY ANALYSIS ===
      const automationOpportunities = [];
      const painPointIndicators = [];

      // Analyze keywords for automation opportunities
      if (keywordCategories.process_keywords.length > 0) {
        automationOpportunities.push('Process Automation');
        painPointIndicators.push('Manual process management');
      }

      if (keywordCategories.government_keywords.length > 0) {
        automationOpportunities.push('Government Contract Management');
        painPointIndicators.push('Complex compliance requirements');
      }

      if (keywordCategories.technology_keywords.length > 3) {
        automationOpportunities.push('IT Infrastructure Automation');
        painPointIndicators.push('Complex technology stack management');
      }

      if (company.estimated_num_employees > 50) {
        automationOpportunities.push('Employee Workflow Automation');
        painPointIndicators.push('Scaling operational challenges');
      }

      // === LEAD QUALIFICATION SCORING ===
      let apolloQualificationScore = 0;

      // Company size scoring (30 points max)
      const empCount = company.estimated_num_employees || 0;
      if (empCount >= 11 && empCount <= 200) apolloQualificationScore += 30;
      else if (empCount >= 201 && empCount <= 500) apolloQualificationScore += 25;
      else if (empCount >= 51 && empCount <= 100) apolloQualificationScore += 20;
      else if (empCount >= 1 && empCount <= 50) apolloQualificationScore += 15;

      // Data completeness (25 points max)
      if (company.phone || company.primary_phone) apolloQualificationScore += 5;
      if (company.linkedin_url) apolloQualificationScore += 5;
      if (company.founded_year) apolloQualificationScore += 3;
      if (keywords.length >= 20) apolloQualificationScore += 7;
      if (keywords.length >= 10) apolloQualificationScore += 5;

      // Technology sophistication (20 points max)
      if (keywordCategories.technology_keywords.length >= 5) apolloQualificationScore += 15;
      else if (keywordCategories.technology_keywords.length >= 3) apolloQualificationScore += 10;
      else if (keywordCategories.technology_keywords.length >= 1) apolloQualificationScore += 5;

      if (keywordCategories.automation_keywords.length > 0) apolloQualificationScore += 5;

      // Business maturity (15 points max)
      const currentYear = new Date().getFullYear();
      const companyAge = company.founded_year ? currentYear - company.founded_year : 0;
      if (companyAge >= 10) apolloQualificationScore += 10;
      else if (companyAge >= 5) apolloQualificationScore += 7;
      else if (companyAge >= 2) apolloQualificationScore += 5;

      if (company.publicly_traded_symbol) apolloQualificationScore += 5;

      // Service complexity (10 points max)
      if (keywordCategories.service_keywords.length >= 3) apolloQualificationScore += 10;
      else if (keywordCategories.service_keywords.length >= 1) apolloQualificationScore += 5;

      // === PERSONALIZATION INSIGHTS ===
      const personalizationInsights = {
        primary_focus_areas: [
          ...keywordCategories.technology_keywords.slice(0, 3),
          ...keywordCategories.service_keywords.slice(0, 2)
        ],
        automation_talking_points: automationOpportunities.slice(0, 3),
        pain_point_indicators: painPointIndicators.slice(0, 3),
        company_maturity: companyAge >= 10 ? 'established' : companyAge >= 5 ? 'mature' : 'growing',
        complexity_level: keywords.length >= 30 ? 'high' : keywords.length >= 15 ? 'medium' : 'basic'
      };

      // === OUTREACH STRATEGY RECOMMENDATIONS ===
      const outreachStrategy = {
        best_contact_method: company.linkedin_url ? 'LinkedIn + Email' : 'Email',
        conversation_starters: [
          `I noticed ${company.name} specializes in ${keywordCategories.service_keywords[0] || keywordCategories.industry_keywords[0] || 'your industry'}`,
          `Your ${empCount}-person team likely faces ${painPointIndicators[0] || 'operational scaling challenges'}`,
          `Companies like yours in ${company.industry} often benefit from ${automationOpportunities[0] || 'process automation'}`
        ].filter(starter => !starter.includes('undefined')),
        value_proposition: `Help ${company.name} automate ${automationOpportunities[0] || 'key processes'} to scale more efficiently`,
        timing_indicators: companyAge <= 5 ? 'high_growth_phase' : empCount >= 50 ? 'scaling_phase' : 'optimization_phase'
      };

      // === COMPILE FINAL ENRICHED DATA ===
      const enrichedCompanyData = {
        // Original data preservation
        ...data,

        // Core company information
        ...coreInfo,

        // Contact information
        ...contactInfo,

        // Business intelligence
        ...businessIntel,

        // Advanced analysis
        apollo_keywords_total: keywords.length,
        apollo_keywords_categorized: keywordCategories,
        apollo_raw_keywords: keywords,

        // Qualification and scoring
        apollo_qualification_score: apolloQualificationScore,
        apollo_company_age: companyAge,
        apollo_complexity_level: personalizationInsights.complexity_level,

        // Automation opportunities
        automation_opportunities_detected: automationOpportunities,
        pain_points_indicated: painPointIndicators,

        // Personalization data
        personalization_insights: personalizationInsights,
        outreach_strategy: outreachStrategy,

        // Data quality indicators
        apollo_data_completeness: Math.round(((company.phone ? 1 : 0) + 
                                            (company.linkedin_url ? 1 : 0) + 
                                            (company.founded_year ? 1 : 0) + 
                                            (keywords.length >= 10 ? 1 : 0) + 
                                            (company.industry ? 1 : 0)) / 5 * 100),

        // Processing metadata
        apollo_enrichment_complete: true,
        apollo_processing_timestamp: new Date().toISOString(),
        apollo_data_quality: apolloQualificationScore >= 70 ? 'excellent' : 
                           apolloQualificationScore >= 50 ? 'good' : 
                           apolloQualificationScore >= 30 ? 'fair' : 'limited'
      };

      formattedResults.push({ json: enrichedCompanyData });

      console.log(`✅ Formatted Apollo data for ${company.name} (Score: ${apolloQualificationScore}/100)`);
    }

  } else {
    // Handle cases with no Apollo data
    const fallbackData = {
      ...data,
      apollo_enrichment_complete: false,
      apollo_enrichment_error: 'No company data returned from Apollo API',
      apollo_qualification_score: 0,
      apollo_data_quality: 'none',
      needs_manual_research: true
    };

    formattedResults.push({ json: fallbackData });
  }
}

console.log(`🏢 Processed ${formattedResults.length} Apollo-enriched company profiles`);
console.log(`✅ High-quality profiles: ${formattedResults.filter(r => r.json.apollo_qualification_score >= 70).length}`);
console.log(`⚡ Good-quality profiles: ${formattedResults.filter(r => r.json.apollo_qualification_score >= 50).length}`);

return formattedResults;

// 📱 Prepare Telegram Notification Summary - CORRECTED
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      telegram_message: "❌ No enrichment data available for notification",
      success: false
    }
  }];
}

// Remove duplicates by Record ID and get unique companies
const uniqueCompanies = [];
const seenRecordIds = new Set();

items.forEach(item => {
  const recordId = item.json.id || item.json.fields?.['Record ID'] || '';
  if (recordId && !seenRecordIds.has(recordId)) {
    seenRecordIds.add(recordId);
    uniqueCompanies.push(item.json.fields || item.json);
  }
});

// Calculate summary statistics
const totalCompanies = uniqueCompanies.length;
const highPriorityCount = uniqueCompanies.filter(company => company['Outreach Priority'] === 'high').length;
const readyForOutreachCount = uniqueCompanies.filter(company => company['Ready for Outreach'] === true).length;
const excellentFitCount = uniqueCompanies.filter(company => company['Automation Fit'] === 'excellent').length;

// Calculate average score
const totalScore = uniqueCompanies.reduce((sum, company) => sum + (company['Final Lead Score'] || 0), 0);
const averageScore = totalCompanies > 0 ? Math.round(totalScore / totalCompanies) : 0;

// Get top 3 companies by score
const topCompanies = uniqueCompanies
  .filter(company => company['Final Lead Score'] >= 85)
  .sort((a, b) => (b['Final Lead Score'] || 0) - (a['Final Lead Score'] || 0))
  .slice(0, 3)
  .map(company => `• ${company['Company Name'] || 'Unknown'} (${company['Final Lead Score'] || 0}/100)`)
  .join('\n');

const topCompaniesList = topCompanies || '• No companies scored above 85 points';

// Count companies with business descriptions
const companiesWithDescriptions = uniqueCompanies.filter(company => 
  company['Business Description'] && company['Business Description'].length > 100
).length;

const telegramMessage = `🚀 **COMPANY ENRICHMENT COMPLETE** 🚀

💬 **READY FOR OUTREACH** 💬

📊 **Results:**
• Companies Processed: ${totalCompanies}
• High Priority: ${highPriorityCount}
• Ready for Outreach: ${readyForOutreachCount}
• Excellent Automation Fit: ${excellentFitCount}

🎯 **Top Performers:**
${topCompaniesList}

📈 **Quality:**
• Average Score: ${averageScore}/100
• Business Descriptions: ${companiesWithDescriptions}

✅ **Next:** Ready for outreach agent workflow

⏰ ${new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })}`;

return [{
  json: {
    telegram_message: telegramMessage,
    total_companies: totalCompanies,
    high_priority_count: highPriorityCount,
    ready_for_outreach_count: readyForOutreachCount,
    excellent_fit_count: excellentFitCount,
    average_score: averageScore,
    companies_with_descriptions: companiesWithDescriptions,
    processing_complete: true
  }
}];

// 🔄 FIXED Comprehensive Data Enrichment Processor - v14.0 - APOLLO ONLY FLOW
const items = $input.all();

if (!items || items.length === 0) {
  return [{
    json: {
      error: 'No Apollo enrichment data received',
      success: false
    }
  }];
}

console.log(`🔄 Processing ${items.length} Apollo formatter items`);

// === GET ORIGINAL LEADS DATA FOR MATCHING ===
const originalLeads = $('🎯 Fetch Leads Ready for Enrichment').all();
console.log(`📋 Found ${originalLeads.length} original leads for matching`);

// Create lookup map for original leads
const leadsLookup = {};
originalLeads.forEach((lead, index) => {
  const leadData = lead.json.fields || lead.json;
  const companyName = leadData['Company Name'] || '';
  const companyWebsite = leadData['Company Website'] || '';
  const recordId = lead.json.id || leadData.id || '';

  console.log(`📝 Lead ${index}: ${leadData['Full Name']} at ${companyName} (ID: ${recordId})`);

  // Create multiple lookup keys for better matching
  const lookupKeys = [
    companyName.toLowerCase().trim(),
    companyWebsite.toLowerCase().replace(/https?:\/\//, '').replace(/\/$/, ''),
    companyName.toLowerCase().replace(/,?\s*(inc|llc|corp|corporation|ltd|limited)\.?$/i, '').trim()
  ].filter(key => key.length > 0);

  lookupKeys.forEach(key => {
    if (!leadsLookup[key]) { // Prevent overwriting - first match wins
      leadsLookup[key] = {
        record_id: recordId,
        full_name: leadData['Full Name'] || '',
        first_name: leadData['First Name'] || '',
        last_name: leadData['Last Name'] || '',
        email: leadData['Email'] || '',
        job_title: leadData['Job Title'] || '',
        seniority_level: leadData['Seniority Level'] || '',
        personal_linkedin_url: leadData['Personal LinkedIn URL'] || '',
        company_name: companyName,
        company_website: companyWebsite,
        original_lead_data: leadData
      };
    }
  });
});

console.log(`🔍 Created ${Object.keys(leadsLookup).length} lookup keys for matching`);

const consolidatedProfiles = [];
const processedCompanies = new Set(); // Track processed companies to avoid duplicates

for (const item of items) {
  try {
    const data = item.json;

    console.log(`🔍 Processing Apollo formatter item with keys:`, Object.keys(data).slice(0, 10));

    // === EXTRACT APOLLO ORGANIZATIONS ===
    const apolloOrganizations = data.organizations || [];
    console.log(`📊 Found ${apolloOrganizations.length} Apollo organizations in this item`);

    // === PROCESS EACH APOLLO ORGANIZATION (AVOID DUPLICATES) ===
    for (const org of apolloOrganizations) {

      // Skip if we've already processed this company
      const companyId = org.id || '';
      if (processedCompanies.has(companyId)) {
        console.log(`⏭️ Skipping duplicate company: ${org.name} (${companyId})`);
        continue;
      }
      processedCompanies.add(companyId);

      // Extract Apollo organization data
      const apolloOrgData = {
        apollo_company_id: org.id || '',
        apollo_company_name: org.name || '',
        apollo_website: org.website_url || '',
        apollo_linkedin: org.linkedin_url || '',
        apollo_phone: org.phone || (org.primary_phone?.number || ''),
        apollo_industry: org.industry || '',
        apollo_employee_count: org.estimated_num_employees || 0,
        apollo_revenue: org.organization_revenue || 0,
        apollo_revenue_printed: org.organization_revenue_printed || '',
        apollo_founded_year: org.founded_year || null,
        apollo_description: org.short_description || '',
        apollo_keywords: org.keywords || [],
        apollo_logo_url: org.logo_url || '',
        apollo_primary_domain: org.primary_domain || ''
      };

      console.log(`🏢 Processing Apollo org: ${apolloOrgData.apollo_company_name}`);

      // === FIND MATCHING ORIGINAL LEAD ===
      let matchedLead = null;
      const apolloLookupKeys = [
        apolloOrgData.apollo_company_name.toLowerCase().trim(),
        apolloOrgData.apollo_website.toLowerCase().replace(/https?:\/\//, '').replace(/\/$/, ''),
        apolloOrgData.apollo_primary_domain.toLowerCase(),
        apolloOrgData.apollo_company_name.toLowerCase().replace(/,?\s*(inc|llc|corp|corporation|ltd|limited)\.?$/i, '').trim()
      ].filter(key => key.length > 0);

      for (const key of apolloLookupKeys) {
        if (leadsLookup[key]) {
          matchedLead = leadsLookup[key];
          console.log(`✅ Matched Apollo company "${apolloOrgData.apollo_company_name}" to lead "${matchedLead.full_name}" (${matchedLead.record_id})`);
          break;
        }
      }

      if (!matchedLead) {
        console.log(`⚠️ No original lead match found for: ${apolloOrgData.apollo_company_name} - SKIPPING`);
        continue; // Skip companies that don't match original leads
      }

      // === CREATE COMPREHENSIVE BUSINESS DESCRIPTION ===
      let businessDescription = '';
      let descriptionSource = 'generated';

      if (apolloOrgData.apollo_description && apolloOrgData.apollo_description.length > 50) {
        businessDescription = apolloOrgData.apollo_description;
        descriptionSource = 'apollo';
        console.log(`📝 Using Apollo description for ${apolloOrgData.apollo_company_name}`);
      } else if (apolloOrgData.apollo_keywords.length > 0) {
        // Generate description from keywords
        const companyName = apolloOrgData.apollo_company_name || 'This company';
        const industry = apolloOrgData.apollo_industry || 'business';
        const employeeCount = apolloOrgData.apollo_employee_count || 0;
        const size = employeeCount > 0 ? `${employeeCount} employees` : 'a dedicated team';
        const founded = apolloOrgData.apollo_founded_year ? `Founded in ${apolloOrgData.apollo_founded_year}, ` : '';
        const topKeywords = apolloOrgData.apollo_keywords.slice(0, 4).join(', ');

        businessDescription = `${founded}${companyName} is a ${industry} company with ${size}. Their expertise includes ${topKeywords}. They focus on providing quality solutions and services to their clients.`;
        descriptionSource = 'generated';
        console.log(`🤖 Generated description for ${apolloOrgData.apollo_company_name}`);
      }

      // === ADVANCED KEYWORD ANALYSIS ===
      const keywordAnalysis = {
        technology_keywords: apolloOrgData.apollo_keywords.filter(k => 
          k.toLowerCase().includes('tech') || k.toLowerCase().includes('software') || 
          k.toLowerCase().includes('cloud') || k.toLowerCase().includes('system') ||
          k.toLowerCase().includes('platform') || k.toLowerCase().includes('digital') ||
          k.toLowerCase().includes('it ') || k.toLowerCase().includes('data') ||
          k.toLowerCase().includes('cyber') || k.toLowerCase().includes('ai')
        ),
        automation_keywords: apolloOrgData.apollo_keywords.filter(k => 
          k.toLowerCase().includes('automation') || k.toLowerCase().includes('workflow') || 
          k.toLowerCase().includes('process') || k.toLowerCase().includes('integration') ||
          k.toLowerCase().includes('optimize') || k.toLowerCase().includes('efficiency')
        ),
        government_keywords: apolloOrgData.apollo_keywords.filter(k => 
          k.toLowerCase().includes('government') || k.toLowerCase().includes('federal') || 
          k.toLowerCase().includes('gsa') || k.toLowerCase().includes('contract') ||
          k.toLowerCase().includes('defense') || k.toLowerCase().includes('classified')
        ),
        service_keywords: apolloOrgData.apollo_keywords.filter(k => 
          k.toLowerCase().includes('service') || k.toLowerCase().includes('support') || 
          k.toLowerCase().includes('consulting') || k.toLowerCase().includes('solution') ||
          k.toLowerCase().includes('management') || k.toLowerCase().includes('advisory')
        ),
        security_keywords: apolloOrgData.apollo_keywords.filter(k => 
          k.toLowerCase().includes('security') || k.toLowerCase().includes('cyber') || 
          k.toLowerCase().includes('compliance') || k.toLowerCase().includes('risk') ||
          k.toLowerCase().includes('protection') || k.toLowerCase().includes('secure')
        )
      };

      // === CALCULATE LEAD SCORES ===
      let finalLeadScore = 0;

      // Company size score (25%)
      const employeeCount = apolloOrgData.apollo_employee_count || 0;
      if (employeeCount >= 11 && employeeCount <= 200) finalLeadScore += 25;
      else if (employeeCount >= 1 && employeeCount <= 50) finalLeadScore += 20;
      else if (employeeCount >= 201) finalLeadScore += 15;
      else finalLeadScore += 5;

      // Data completeness score (25%)
      let completenessScore = 0;
      if (apolloOrgData.apollo_company_name) completenessScore += 5;
      if (businessDescription.length > 200) completenessScore += 10;
      else if (businessDescription.length > 100) completenessScore += 8;
      else if (businessDescription.length > 50) completenessScore += 6;
      if (apolloOrgData.apollo_keywords.length >= 20) completenessScore += 5;
      else if (apolloOrgData.apollo_keywords.length >= 10) completenessScore += 3;
      if (apolloOrgData.apollo_phone) completenessScore += 2;
      if (apolloOrgData.apollo_revenue > 0) completenessScore += 2;
      finalLeadScore += completenessScore;

      // Industry relevance (20%)
      const industry = apolloOrgData.apollo_industry.toLowerCase();
      if (industry.includes('technology') || industry.includes('software') || industry.includes('information')) {
        finalLeadScore += 20;
      } else if (industry.includes('financial') || industry.includes('healthcare') || industry.includes('professional')) {
        finalLeadScore += 15;
      } else if (industry.includes('manufacturing') || industry.includes('retail') || industry.includes('consulting')) {
        finalLeadScore += 10;
      } else {
        finalLeadScore += 5;
      }

      // Automation readiness (20%)
      const totalAutomationIndicators = keywordAnalysis.technology_keywords.length + 
                                       keywordAnalysis.automation_keywords.length + 
                                       keywordAnalysis.service_keywords.length;

      if (totalAutomationIndicators >= 15) finalLeadScore += 20;
      else if (totalAutomationIndicators >= 10) finalLeadScore += 16;
      else if (totalAutomationIndicators >= 6) finalLeadScore += 12;
      else if (totalAutomationIndicators >= 3) finalLeadScore += 8;
      else if (totalAutomationIndicators >= 1) finalLeadScore += 4;
      else finalLeadScore += 1;

      // Data source quality bonus (10%)
      let dataSourceBonus = 0;
      if (apolloOrgData.apollo_keywords.length >= 30) dataSourceBonus += 5;
      else if (apolloOrgData.apollo_keywords.length >= 15) dataSourceBonus += 3;
      if (businessDescription.length > 300) dataSourceBonus += 3;
      if (apolloOrgData.apollo_revenue > 0) dataSourceBonus += 2;
      finalLeadScore += dataSourceBonus;

      // === AUTOMATION FIT ASSESSMENT ===
      let automationFit = 'limited';
      if (totalAutomationIndicators >= 15 && employeeCount >= 20) automationFit = 'excellent';
      else if (totalAutomationIndicators >= 10 && employeeCount >= 10) automationFit = 'good';
      else if (totalAutomationIndicators >= 5 || employeeCount >= 5) automationFit = 'fair';

      // === PAIN POINTS IDENTIFICATION ===
      const painPoints = [];

      if (employeeCount >= 100) {
        painPoints.push('Enterprise-scale coordination and communication challenges');
      } else if (employeeCount >= 50) {
        painPoints.push('Large team coordination and communication challenges');
      } else if (employeeCount >= 20) {
        painPoints.push('Growing operational complexity and manual bottlenecks');
      } else if (employeeCount >= 10) {
        painPoints.push('Process standardization and efficiency needs');
      } else {
        painPoints.push('Resource optimization and growth scaling challenges');
      }

      // Industry-specific pain points
      if (industry.includes('technology') || industry.includes('software')) {
        painPoints.push('Complex technology integration and maintenance overhead');
      } else if (industry.includes('financial')) {
        painPoints.push('Regulatory compliance and reporting complexity');
      } else if (keywordAnalysis.government_keywords.length > 0) {
        painPoints.push('Federal compliance and procurement complexity');
      }

      // === AUTOMATION OPPORTUNITIES ===
      const opportunities = [];

      if (employeeCount >= 20) {
        opportunities.push('Employee workflow and communication automation');
      }
      if (keywordAnalysis.service_keywords.length >= 3) {
        opportunities.push('Service delivery and client management automation');
      }
      if (keywordAnalysis.technology_keywords.length >= 5) {
        opportunities.push('Technology integration and system optimization');
      }
      if (keywordAnalysis.government_keywords.length > 0) {
        opportunities.push('Government compliance and reporting automation');
      }
      if (keywordAnalysis.security_keywords.length >= 2) {
        opportunities.push('Security monitoring and compliance automation');
      }

      // Default opportunities
      if (opportunities.length === 0) {
        opportunities.push('Process optimization and operational efficiency automation');
      }

      // === OUTREACH READINESS ASSESSMENT ===
      const isReadyForOutreach = finalLeadScore >= 40 && 
                                apolloOrgData.apollo_company_name && 
                                businessDescription.length > 50;

      const outreachPriority = finalLeadScore >= 75 ? 'high' : 
                              finalLeadScore >= 55 ? 'medium' : 'low';

      const dataQuality = finalLeadScore >= 70 ? 'high' : 
                         finalLeadScore >= 50 ? 'medium' : 'low';

      // === COMPILE ENRICHED COMPANY PROFILE ===
      const enrichedProfile = {
        // === PRESERVE ORIGINAL LEAD DATA ===
        record_id: matchedLead.record_id,
        full_name: matchedLead.full_name,
        first_name: matchedLead.first_name,
        last_name: matchedLead.last_name,
        email: matchedLead.email,
        job_title: matchedLead.job_title,
        seniority_level: matchedLead.seniority_level,
        personal_linkedin_url: matchedLead.personal_linkedin_url,

        // === CONSOLIDATED COMPANY DATA ===
        company_name: apolloOrgData.apollo_company_name,
        company_website: apolloOrgData.apollo_website,
        company_linkedin: apolloOrgData.apollo_linkedin,
        company_phone: apolloOrgData.apollo_phone,
        company_industry: apolloOrgData.apollo_industry,
        company_size: employeeCount,
        company_revenue: apolloOrgData.apollo_revenue,
        company_revenue_display: apolloOrgData.apollo_revenue_printed,
        founded_year: apolloOrgData.apollo_founded_year,

        // === COMPREHENSIVE BUSINESS DESCRIPTION ===
        business_description: businessDescription,
        apollo_company_id: apolloOrgData.apollo_company_id,

        // === ANALYSIS AND INSIGHTS ===
        pain_points_detected: painPoints.slice(0, 2).join('; '),
        opportunities_identified: opportunities.slice(0, 3).join('; '),

        // === SCORING AND ASSESSMENT ===
        final_lead_score: Math.round(finalLeadScore),
        automation_fit: automationFit,

        // === OUTREACH READINESS ===
        ready_for_outreach: isReadyForOutreach,
        outreach_priority: outreachPriority,
        best_approach: 'LinkedIn DM',
        data_quality: dataQuality,

        // === QUICK REFERENCE FOR OUTREACH TEAM ===
        quick_pitch: `${matchedLead.full_name} at ${apolloOrgData.apollo_company_name} - ${employeeCount} employees in ${industry} - ${automationFit} automation fit`,

        // === ENRICHMENT METADATA ===
        enrichment_complete: true,
        enrichment_timestamp: new Date().toISOString(),
        processing_version: '14.0_apollo_only_no_duplicates',

        // === DATA SOURCES SUMMARY ===
        data_sources: ['apollo_organization'],

        // === KEYWORD INTELLIGENCE FOR OUTREACH ===
        keyword_categories: {
          technology: keywordAnalysis.technology_keywords.slice(0, 5),
          automation: keywordAnalysis.automation_keywords.slice(0, 3),
          government: keywordAnalysis.government_keywords.slice(0, 3),
          services: keywordAnalysis.service_keywords.slice(0, 5),
          security: keywordAnalysis.security_keywords.slice(0, 3)
        },

        // === ENRICHMENT QUALITY METRICS ===
        enrichment_quality: {
          apollo_data_available: true,
          linkedin_data_available: false,
          business_description_source: descriptionSource,
          total_keywords: apolloOrgData.apollo_keywords.length,
          automation_indicators: totalAutomationIndicators,
          data_completeness_score: Math.round(completenessScore),
          original_lead_matched: true
        }
      };

      consolidatedProfiles.push({ json: enrichedProfile });

      console.log(`✅ Enriched: ${apolloOrgData.apollo_company_name} - Lead: ${matchedLead.full_name} (${matchedLead.record_id}) - Score: ${Math.round(finalLeadScore)}`);
    }

  } catch (error) {
    console.error(`❌ Error processing Apollo item:`, error.message);
    consolidatedProfiles.push({ 
      json: { 
        error: `Comprehensive enrichment failed: ${error.message}`,
        original_data: item.json,
        processing_version: '14.0_apollo_only_no_duplicates'
      } 
    });
  }
}

console.log(`🚀 COMPREHENSIVE ENRICHMENT COMPLETE (APOLLO ONLY, NO DUPLICATES):`);
console.log(`   📊 Total Processed: ${consolidatedProfiles.length}`);
console.log(`   🔥 High Priority: ${consolidatedProfiles.filter(p => p.json.outreach_priority === 'high').length}`);
console.log(`   ⚡ Medium Priority: ${consolidatedProfiles.filter(p => p.json.outreach_priority === 'medium').length}`);
console.log(`   🚀 Ready for Outreach: ${consolidatedProfiles.filter(p => p.json.ready_for_outreach).length}`);
console.log(`   🆔 With Original Lead Match: ${consolidatedProfiles.filter(p => p.json.record_id).length}`);
console.log(`   📈 Average Score: ${Math.round(consolidatedProfiles.reduce((sum, p) => sum + (p.json.final_lead_score || 0), 0) / consolidatedProfiles.length)}`);

return consolidatedProfiles;
